glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
  precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
  in vec4 v_color;
  #if USE_TEXTURE
  in vec2 v_uv0;
  uniform sampler2D texture;
  #endif
  uniform LoopShader { float waveSpeed; };
void main() {
  vec4 bg = vec4(1.0);
  float waveAmplitude = 0.05;
  float tileCount = 2.0;
  float PI = 3.14159;
  float time = mod(waveSpeed, 2.0 * PI);
  vec2 p = v_uv0;
  p.y += waveAmplitude * sin((p.x + time) * tileCount * 2.0 * PI);
  p = fract(p);
  #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, p);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, p + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    bg.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    bg.a *= texture_tmp.a;
  #else
    bg *= texture_tmp;
  #endif
  #endif
  bg *= v_color;
  ALPHA_TEST(bg);
  #if USE_BGRA
    gl_FragColor = bg.bgra;
  #else
    gl_FragColor = bg.rgba;
  #endif
}

